import { thunderIDMiddleware } from '@thunderid/nextjs/middleware';

export const middleware = thunderIDMiddleware();

export const config = {
  matcher: [
    '/((?!_next|[^?]*\.(?:html?|css|js(?!on)|jpe?g|webp|png|gif|svg|ttf|woff2?|ico|csv|docx?|xlsx?|zip|webmanifest)).*)',
    '/(api|trpc)(.*)',
  ],
};

import { ThunderIDProvider } from '@thunderid/nextjs/server';

export default function RootLayout({ children }: { children: React.ReactNode }) {
  return (
    <html lang="en">
      <body>
        <ThunderIDProvider>
          {children}
        </ThunderIDProvider>
      </body>
    </html>
  );
}

import { SignedIn, SignedOut, SignInButton, SignOutButton, UserDropdown } from '@thunderid/nextjs';

export default function Home() {
  return (
    <main>
      <SignedIn>
        <UserDropdown />
        <SignOutButton />
      </SignedIn>
      <SignedOut>
        <SignInButton />
      </SignedOut>
    </main>
  );
}
